function otx_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function otx_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function otx_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;} function otx_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
