function otx_where($src,&$p){$from=isset($src['tgl_awal'])&&$src['tgl_awal']!==''?$src['tgl_awal']:date('Y-m-01');$to=isset($src['tgl_akhir'])&&$src['tgl_akhir']!==''?$src['tgl_akhir']:date('Y-m-t');$w=" WHERE ot.overtime_date BETWEEN ? AND ? ";array_push($p,$from,$to);if(isset($src['employee_id'])&&$src['employee_id']!==''){$w.=" AND ot.employee_id=? ";$p[]=(int)$src['employee_id'];}foreach(array('department_code','cost_center_code','overtime_type','overtime_status','request_source') as $k){if(isset($src[$k])&&$src[$k]!==''){$w.=" AND ot.$k=? ";$p[]=$src[$k];}}$impact=isset($src['impact_type'])?$src['impact_type']:'';if($impact==='PAYABLE')$w.=" AND ot.payable_hours>0 ";elseif($impact==='UNAPPROVED')$w.=" AND ot.overtime_status IN ('DRAFT','REQUESTED') ";elseif($impact==='REJECTED')$w.=" AND ot.overtime_status='REJECTED' ";elseif($impact==='PAYROLL_POSTED')$w.=" AND ot.overtime_status='POSTED' ";elseif($impact==='NO_ATTENDANCE_REF')$w.=" AND ot.attendance_id IS NULL ";if(isset($src['keyword'])&&$src['keyword']!==''){$kw='%'.$src['keyword'].'%';$w.=" AND (ot.overtime_no LIKE ? OR ot.employee_no LIKE ? OR e.full_name LIKE ? OR ot.overtime_reason LIKE ? OR ot.sap_reference LIKE ? OR d.nm_dept LIKE ?) ";for($i=0;$i<6;$i++)$p[]=$kw;}return $w;}
