case 'export':$initial=ob_get_level();ob_start();error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$p=array();$w=otx_where($_GET,$p);$rows=$db->query("SELECT ot.*,e.full_name,e.employee_group,d.nm_dept,cc.cost_center_name FROM erp_overtime ot JOIN erp_employee_master e ON e.id=ot.employee_id LEFT JOIN dept d ON d.kd_dept=ot.department_code LEFT JOIN erp_cost_center cc ON cc.cost_center_code=ot.cost_center_code $w ORDER BY ot.overtime_date DESC,ot.overtime_no DESC",$p);$excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Overtime Report'));$heads=array(erp_export_label("No"),erp_export_label("Overtime No"),erp_export_label("Date"),erp_export_label("Employee"),erp_export_label("Department"),erp_export_label("Cost Center"),erp_export_label("Attendance"),erp_export_label("Planned Start"),erp_export_label("Planned End"),erp_export_label("Actual Start"),erp_export_label("Actual End"),erp_export_label("Requested Hours"),erp_export_label("Approved Hours"),erp_export_label("Payable Hours"),erp_export_label("Multiplier"),erp_export_label("Hourly Rate"),erp_export_label("Estimated Amount"),erp_export_label("Type"),erp_export_label("Source"),erp_export_label("Status"),erp_export_label("Requested By"),erp_export_label("Approved By"),erp_export_label("Posted By"),erp_export_label("Reason"),erp_export_label("Reject Reason"),erp_export_label("SAP Ref"),erp_export_label("Updated By"));foreach($heads as $i=>$h)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$h);$rn=5;$n=1;foreach($rows as $r){$vals=array($n++,$r->overtime_no,$r->overtime_date,$r->employee_no.' - '.$r->full_name,($r->department_code?:'').' - '.($r->nm_dept?:''),($r->cost_center_code?:'').' - '.($r->cost_center_name?:''),$r->attendance_no,$r->planned_start,$r->planned_end,$r->actual_start,$r->actual_end,$r->requested_hours,$r->approved_hours,$r->payable_hours,$r->rate_multiplier,$r->hourly_rate,$r->estimated_amount,$r->overtime_type,$r->request_source,$r->overtime_status,$r->requested_by,$r->approved_by,$r->posted_by,$r->overtime_reason,$r->reject_reason,$r->sap_reference,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$rn,$v);$rn++;}erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('OVERTIME REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rn-1),'column_count'=>count($heads),'decimal_columns'=>array('L','M','N','O'),'money_columns'=>array('P','Q'),'filters'=>array('Date'=>otx_g('tgl_awal',date('Y-m-01')).' s/d '.otx_g('tgl_akhir',date('Y-m-t'))),'widths'=>array('B'=>20,'D'=>30,'E'=>26,'F'=>30,'H'=>20,'I'=>20,'J'=>20,'K'=>20,'X'=>36,'Y'=>30)));$tmp=erpkb_excel_temp_file('overtime_report_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="overtime_report_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
